"use client";
import Link from 'next/link';
import { useState, useEffect } from 'react';
import { Wallet } from 'lucide-react';
import { ethers } from 'ethers';

export default function Navbar() {
    const [account, setAccount] = useState<string | null>(null);
    const [isConnecting, setIsConnecting] = useState(false);

    useEffect(() => {
        checkIfWalletIsConnected();
    }, []);

    const checkIfWalletIsConnected = async () => {
        if (typeof window !== 'undefined' && window.ethereum) {
            try {
                const provider = new ethers.BrowserProvider(window.ethereum as ethers.Eip1193Provider);
                const accounts = await provider.listAccounts();
                if (accounts.length > 0) {
                    setAccount(accounts[0].address);
                }
            } catch (error) {
                console.error("Error checking wallet connection", error);
            }
        }
    };

    const connectWallet = async () => {
        if (typeof window !== 'undefined' && window.ethereum) {
            try {
                setIsConnecting(true);
                const provider = new ethers.BrowserProvider(window.ethereum as ethers.Eip1193Provider);
                await provider.send("eth_requestAccounts", []);
                const signer = await provider.getSigner();
                const address = await signer.getAddress();
                setAccount(address);
            } catch (error) {
                console.error("Error connecting wallet", error);
            } finally {
                setIsConnecting(false);
            }
        } else {
            alert("Please install MetaMask!");
        }
    };

    const formatAddress = (addr: string) => {
        return `${addr.substring(0, 6)}...${addr.substring(addr.length - 4)}`;
    };
    return (
        <nav className="fixed w-full z-50 top-0 left-0 border-b border-white/10 bg-black/50 backdrop-blur-md">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                <div className="flex justify-between items-center h-16">
                    <div className="flex-shrink-0 flex items-center">
                        <Link href="/" className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-emerald-400 hover:opacity-80 transition-opacity">
                            TrustChain
                        </Link>
                    </div>
                    <div className="flex items-center space-x-4">
                        <Link href="/create" className="text-gray-300 hover:text-white transition-colors text-sm font-medium mr-4">
                            Create Escrow
                        </Link>
                        {account ? (
                            <Link href="/dashboard" className="text-gray-300 hover:text-white transition-colors text-sm font-medium mr-4">
                                Dashboard
                            </Link>
                        ) : null}

                        <button
                            onClick={account ? undefined : connectWallet}
                            disabled={isConnecting}
                            className="inline-flex items-center justify-center px-4 py-2 border border-transparent rounded-lg shadow-sm text-sm font-medium text-black bg-white hover:bg-gray-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-black focus:ring-white transition-all transform hover:scale-105 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            <Wallet className="w-4 h-4 mr-2" />
                            {isConnecting ? 'Connecting...' : account ? formatAddress(account) : 'Connect Wallet'}
                        </button>
                    </div>
                </div>
            </div>
        </nav>
    );
}
